// Форматирует payload от parser_runner.py в HTML-сообщение для Telegram
const b = $input.first().json.body || $input.first().json;
const run_id = b.run_id || '?';
const status = (b.status || 'unknown').toLowerCase();
const totals = b.totals || {};
const errors_count = b.errors_count || 0;
const chat_id = b.chat_id;  // приходит из parser_runner.py (TG_CHAT_ID из .env)

const STATUS_EMOJI = {
  ok: '✅', partial: '⚠️', failed: '❌', running: '⏳'
};
const icon = STATUS_EMOJI[status] || '📦';

// Сводка по платформам
let platforms_text = '';
let total_upserted = 0;
for (const [pl, t] of Object.entries(totals)) {
  const found = t.found || 0;
  const unique = t.unique || 0;
  const upserted = t.upserted || 0;
  total_upserted += upserted;
  platforms_text += `\n  <b>${pl}</b>: found=${found}, unique=${unique}, <b>upserted=${upserted}</b>`;
}

const lines = [
  `${icon} <b>Парсер anti-ms-mp</b>`,
  `Прогон <code>#${run_id}</code> завершён со статусом <b>${status}</b>.`,
  '',
  `<b>Карточек залито в Supabase:</b> ${total_upserted}`,
  platforms_text || '  (нет данных)',
  '',
  errors_count > 0 ? `⚠️ Ошибок: <b>${errors_count}</b>` : '',
  `📊 <a href="https://anti-ms-mp.vercel.app/anti-ms-dashboard/">Дашборд</a>`,
].filter(Boolean);

return [{ json: { chat_id, text: lines.join('\n') } }];
